import{_ as a,o as e,c as s,e as n}from"./app-410d86ed.js";const i={},t=n(`<h1 id="git修改提交记录中的作者信息" tabindex="-1"><a class="header-anchor" href="#git修改提交记录中的作者信息" aria-hidden="true">#</a> Git修改提交记录中的作者信息</h1><blockquote><p>背景：在主机中配置了多个git账户信息，由于平时开发公司代码比较多，将公司账户信息配置在<code>~/.gitconfig</code>文件中，偶尔写一些自己的开源项目，使用的自己的账户信息，将信息配置在项目目录下的<code>.git/config</code>文件中，有次在开发项目时忘记配置用户信息，导致提交记录中的用户信息混乱。</p></blockquote><h2 id="可以分为一下几种情况进行讨论" tabindex="-1"><a class="header-anchor" href="#可以分为一下几种情况进行讨论" aria-hidden="true">#</a> 可以分为一下几种情况进行讨论</h2><p><strong>以下几种情况都需要先修改用户信息</strong></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> config user.name <span class="token string">&quot;xxx&quot;</span>
<span class="token function">git</span> config user.email <span class="token string">&quot;xxx@yy.zz&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_1-只有最近一次提交记录的用户信息不正确" tabindex="-1"><a class="header-anchor" href="#_1-只有最近一次提交记录的用户信息不正确" aria-hidden="true">#</a> 1. 只有最近一次提交记录的用户信息不正确</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># amend修改commit信息，no-edit不编辑提交描述信息，reset-author重置作者信息（用户名与邮箱）</span>
<span class="token function">git</span> commit <span class="token parameter variable">--amend</span> --no-edit --reset-author
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-最近几次提交记录的用户信息都不正确" tabindex="-1"><a class="header-anchor" href="#_2-最近几次提交记录的用户信息都不正确" aria-hidden="true">#</a> 2. 最近几次提交记录的用户信息都不正确</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># $REV 为提交记录的hash值，该命令会修改该提交记录以及之后的所有commit信息</span>
<span class="token function">git</span> rebase <span class="token parameter variable">-i</span> <span class="token variable">$REV</span> <span class="token parameter variable">--exec</span> <span class="token string">&quot;git commit --amend --no-edit --reset-author&quot;</span>
<span class="token comment"># rebase操作执行时会弹出一个编辑窗口，直接保存</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-所有提交记录的用户信息都不正确" tabindex="-1"><a class="header-anchor" href="#_3-所有提交记录的用户信息都不正确" aria-hidden="true">#</a> 3. 所有提交记录的用户信息都不正确</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 该命令会修改从首次提交记录开始的所有commit信息</span>
<span class="token function">git</span> rebase <span class="token parameter variable">-r</span> <span class="token parameter variable">--root</span> <span class="token parameter variable">--exec</span> <span class="token string">&quot;git commit --amend --no-edit --reset-author&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_4-中间的几次提交记录的用户信息不正确" tabindex="-1"><a class="header-anchor" href="#_4-中间的几次提交记录的用户信息不正确" aria-hidden="true">#</a> 4. 中间的几次提交记录的用户信息不正确</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># $REV 为提交记录的hash值，该命令会修改该提交记录以及之后的所有commit信息</span>
<span class="token function">git</span> rebase <span class="token parameter variable">-i</span> <span class="token variable">$REV</span> <span class="token parameter variable">--exec</span> <span class="token string">&quot;git commit --amend --no-edit --reset-author&quot;</span>
<span class="token comment"># rebase操作执行时会弹出一个编辑窗口，删除掉不需要修改的提交记录（根据提交描述信息选择），保存</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>修改完成后如果需要提交到远程仓库</strong></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> push <span class="token parameter variable">--force</span> <span class="token parameter variable">--all</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div>`,15),r=[t];function d(c,o){return e(),s("div",null,r)}const p=a(i,[["render",d],["__file","gitModifyAuthor.html.vue"]]);export{p as default};
